sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.pp-page {
  font-family: Inter, "Helvetica Neue", sans-serif;
  background: #f5f7fc;
  overflow-x: hidden;
}

/* CONTAINER */

.container {
  width: 100%;
  max-width: 1180px;
  margin: auto;
  padding: 0 32px;
}

/* HERO */

.pp-hero {
  position: relative;
  overflow: hidden;
  background: linear-gradient(
    90deg,
    #116AF8 0%,
    #0A50F5 100%
  );

  padding: 70px 0 120px;

  border-radius: 0 0 32px 32px;
}

/* GRID */

.pp-grid {
  position: absolute;
  inset: 0;
  opacity: .12;

  background-image:
    linear-gradient(
      rgba(255,255,255,.5) 1px,
      transparent 1px
    ),
    linear-gradient(
      90deg,
      rgba(255,255,255,.5) 1px,
      transparent 1px
    );

  background-size: 78px 78px;
}

/* FLOATING CIRCLE */

.pp-circle {
  position: absolute;
  left: 80px;
  top: 340px;

  width: 150px;
  height: 150px;

  border-radius: 50%;
  border: 2px solid rgba(255,255,255,.08);
}

/* HERO LAYOUT */

.pp-hero-content {
  position: relative;
  z-index: 10;

  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 60px;
}

/* LEFT */

.pp-left {
  max-width: 620px;
  padding: 10px 18px;
}

.pp-badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;

  padding: 5px 10px;
}

  .pp-badge:hover {
    transform: translateY(-2px) scale(1.01);
}
.pp-left h1 {
  color: white;

  font-size: 64px;
  font-weight: 800;
  line-height: 1.05;

  margin: 28px 0 20px;
}

.pp-left p {
  color: rgba(255,255,255,.9);

  font-size: 18px;
  line-height: 1.8;

  max-width: 520px;
}

/* BUTTONS */

.pp-actions {
  margin-top: 32px;

  display: flex;
  gap: 16px;
}

.btn-primary,
.btn-secondary {
  height: 52px;

  padding: 0 26px;

  border-radius: 14px;

  font-size: 16px;
  font-weight: 600;

  cursor: pointer;

  transition: all .25s ease;
}

.btn-primary {
  background: white;
  border: none;
  color: #116AF8;
}

.btn-primary:hover {
  transform: translateY(-2px);
}

.btn-secondary {
  background: rgba(255,255,255,.08);
  border: 1px solid rgba(255,255,255,.25);
  color: white;
}

.btn-secondary:hover {
  background: rgba(255,255,255,.12);
}

/* RIGHT */

.pp-right {
  position: relative;
}

.security-card {
  width: 310px;
  height: 310px;

  border-radius: 28px;

  background: linear-gradient(
    180deg,
    rgba(255,255,255,.18),
    rgba(255,255,255,.08)
  );

  border: 1px solid rgba(255,255,255,.15);

  display: flex;
  align-items: center;
  justify-content: center;

  position: relative;

  backdrop-filter: blur(20px);
}

/* DECORATIVE OUTLINE CARD */

.security-card:before {
  content: "";

  position: absolute;

  width: 150px;
  height: 150px;

  top: -35px;
  right: -20px;

  border-radius: 24px;

  border: 2px solid rgba(255,255,255,.08);

  transform: rotate(10deg);
}

/* FLOATING ICONS */

.floating-lock,
.floating-check {
  position: absolute;

  width: 48px;
  height: 48px;

  border-radius: 14px;

  background: rgba(255,255,255,.15);
  border: 1px solid rgba(255,255,255,.2);

  display: flex;
  align-items: center;
  justify-content: center;

  color: white;
  font-size: 18px;
}

.floating-lock {
  top: -12px;
  right: -12px;

  animation: lockFloat 4s ease-in-out infinite;
}

.floating-check {
  left: -12px;
  bottom: 38px;

  animation: checkFloat 3s ease-in-out infinite;
}

@keyframes lockFloat {
  0% {
    transform: translateY(0px);
  }

  50% {
    transform: translateY(-15px);
  }

  100% {
    transform: translateY(0px);
  }
}

@keyframes checkFloat {
  0% {
    transform: translateY(0px);
  }

  50% {
    transform: translateY(12px);
  }

  100% {
    transform: translateY(0px);
  }
}

/* HERO CURVE */

.hero-curve {
  position: absolute;
  bottom: -1px;
  left: 0;

  width: 100%;
  height: 80px;

  background: #f5f7fc;

  clip-path: polygon(
    0 55%,
    20% 20%,
    50% 0,
    80% 20%,
    100% 55%,
    100% 100%,
    0 100%
  );
}

/* FEATURES */

.pp-features {
  position: relative;
  z-index: 20;

  margin-top: -60px;
}

.feature-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 28px;
}

.feature-card {
  background: white;
  border-radius: 20px;
  padding: 26px;
  min-height: 170px;

  box-shadow:
    0 15px 40px rgba(0,0,0,.08);

  transition:
    transform .3s ease,
    box-shadow .3s ease;

  cursor: pointer;
}

.feature-card:hover {
  transform: translateY(-8px);

  box-shadow:
    0 25px 60px rgba(17,106,248,.15);
}

.feature-card:hover .icon-box {
  transform: scale(1.08);
}

.icon-box {
  width: 48px;
  height: 48px;

  border-radius: 14px;

  background: linear-gradient(
    180deg,
    #116AF8,
    #0A50F5
  );

  display: flex;
  align-items: center;
  justify-content: center;

  color: white;
  font-size: 18px;

  transition: transform .3s ease;
}

.feature-card h3 {
  margin-top: 18px;

  font-size: 18px;
  font-weight: 700;

  color: #101828;
}

.feature-card p {
  margin-top: 8px;

  font-size: 14px;
  line-height: 1.6;

  color: #667085;
}

/* RESPONSIVE */

@media (max-width: 1200px) {

  .pp-hero-content {
    flex-direction: column;
    text-align: center;
  }

  .pp-left {
    max-width: 100%;
  }

  .pp-left p {
    margin: 0 auto;
  }

  .pp-actions {
    justify-content: center;
  }

  .feature-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .pp-left h1 {
    font-size: 54px;
  }
}

@media (max-width: 768px) {

  .container {
    padding: 0 20px;
  }

  .pp-hero {
    padding: 60px 0 110px;
  }

  .pp-left h1 {
    font-size: 42px;
  }

  .pp-left p {
    font-size: 16px;
  }

  .security-card {
    width: 260px;
    height: 260px;
  }

  .pp-actions {
    flex-direction: column;
    align-items: center;
  }

  .btn-primary,
  .btn-secondary {
    width: 100%;
    max-width: 260px;
  }

  .feature-grid {
    grid-template-columns: 1fr;
  }

  .pp-features {
    margin-top: -40px;
  }
}
/* ==========================
   CONTENT AREA
========================== */

.pp-content-section {
  padding: 50px 0 80px;
}

.pp-layout {
  display: flex;
  gap: 40px;
  align-items: flex-start;
}

/* ==========================
   SIDEBAR
========================== */

.pp-sidebar {
  width: 280px;
  flex: 0 0 280px;
}

.toc-card {
  background: #fff;
  border-radius: 18px;
  padding: 20px;
  box-shadow: 0 8px 24px rgba(15, 23, 42, .08);
  position: sticky;
  top: 30px;
}

.toc-card h3 {
  margin: 0 0 20px;
  font-size: 20px;
  font-weight: 700;
  color: #1e293b;
}

.toc-card h3 i {
  margin-right: 10px;
  color: #116AF8;
}

.toc-card ul {
  list-style: none;
  padding: 0;
  margin: 0;
}

.toc-card li {
  display: flex;
  align-items: center;
  gap: 12px;

  padding: 14px 14px;
  border-radius: 12px;

  color: #475569;
  font-size: 14px;
  font-weight: 500;

  cursor: pointer;
  transition: all .3s ease;
}

.toc-card li:hover {
  background: #f3f7ff;
  color: #116AF8;
}

.toc-card li.active {
  background: linear-gradient(
    90deg,
    #116AF8,
    #0A50F5
  );

  color: white;

  box-shadow:
    0 8px 20px rgba(17,106,248,.25);
}

.help-box {
  margin-top: 24px;

  background: #eef4ff;
  border: 1px solid #d8e5ff;

  border-radius: 16px;
  padding: 18px;
}

.help-box h4 {
  margin: 0;
  font-size: 16px;
  font-weight: 700;
}

.help-box p {
  margin: 8px 0 16px;
  font-size: 13px;
  color: #64748b;
}

.help-box button {
  width: 100%;
  height: 42px;

  border: none;
  border-radius: 10px;

  background: linear-gradient(
    90deg,
    #116AF8,
    #0A50F5
  );

  color: white;
  font-weight: 600;
}

/* ==========================
   MAIN CONTENT
========================== */

.pp-main-content {
  flex: 1;
  min-width:0;
}

/* ==========================
   POLICY CARD
========================== */

.policy-card {
  background: white;

  border-radius: 18px;

  overflow: hidden;

  margin-bottom: 28px;

  box-shadow:
    0 10px 30px rgba(15,23,42,.08);
}

.policy-header {
  background: linear-gradient(
    90deg,
    #116AF8,
    #0A50F5
  );

  padding: 18px 26px;

  display: flex;
  align-items: center;
  gap: 14px;
}

.policy-icon {
  width: 42px;
  height: 42px;

  border-radius: 50%;

  background: rgba(255,255,255,.15);

  display: flex;
  align-items: center;
  justify-content: center;

  color: white;
}

.policy-header h2 {
  margin: 0;

  color: white;

  font-size: 20px;
  font-weight: 700;
}

.policy-body {
  padding: 28px;
}

.policy-body p {
  color: #334155;

  line-height: 1.9;

  font-size: 16px;
}

/* IMPORTANT BOX */

.important-box {
  margin-top: 25px;

  background: #f2f7ff;

  border-left: 4px solid #116AF8;

  padding: 18px 20px;

  border-radius: 12px;

  color: #334155;
}

/* SUBSECTIONS */

.policy-subsection {
  margin-bottom: 35px;
}

.policy-subsection h3 {
  position: relative;

  margin-bottom: 14px;

  padding-left: 16px;

  font-size: 24px;
  font-weight: 700;
}

.policy-subsection h3:before {
  content: "";

  position: absolute;

  left: 0;
  top: 2px;

  width: 5px;
  height: 24px;

  border-radius: 50px;

  background: #116AF8;
}

/* RESPONSIVE */

@media (max-width: 992px) {

  .pp-layout {
    flex-direction: column;
  }

  .pp-sidebar {
    width: 100%;
  }

  .toc-card {
    position: relative;
    top: auto;
  }
}
/* MINI INFO CARDS */

.info-mini-grid {
  display: flex;
  gap: 12px;
  margin-top: 20px;
  padding-bottom:10px;
}

.info-mini-card {
  flex: 1;

  min-height: 66px;

  border-radius: 12px;

  border: 1px solid #dbe4f0;
  background: #f8fafc;

  padding: 14px;

  display: flex;
  flex-direction: column;
  justify-content: center;

  transition: all .25s ease;
}

.info-mini-card:hover {
  transform: translateY(-3px);

  box-shadow:
    0 10px 20px rgba(17,106,248,.08);
}

.mini-icon {
  width: 28px;
  height: 28px;

  border-radius: 8px;

  display: flex;
  align-items: center;
  justify-content: center;

  color: #fff;

  font-size: 12px;

  margin-bottom: 8px;
}

.account-icon {
  background: linear-gradient(
    135deg,
    #4F46E5,
    #3B82F6
  );
}

.migration-icon {
  background: linear-gradient(
    135deg,
    #EC4899,
    #A855F7
  );
}

.info-mini-card span {
  font-size: 12px;
  font-weight: 600;
  color: #0f172a;
}
.section-intro {
    margin-bottom: 28px;
    color: #475569;
    font-size: 15px;
    line-height: 1.7;
}

.usage-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.usage-list li {
    position: relative;

    padding-left: 28px;

    margin-bottom: 28px;

    color: #334155;
    font-size: 15px;
    line-height: 1.8;
}

.usage-list li:last-child {
    margin-bottom: 0;
}

.usage-list li:before {
    content: "";

    position: absolute;

    left: 0;
    top: 7px;

    width: 14px;
    height: 14px;

    border: 2px solid #116AF8;
    border-radius: 50%;

    background: #fff;
}

.usage-list li:after {
    content: "";

    position: absolute;

    left: 5px;
    top: 12px;

    width: 4px;
    height: 4px;

    border-radius: 50%;

    background: #116AF8;
}
